def get_section_mapping(query: str):
    query_lower = query.lower().strip()

    # Remove common words to get the core query
    query_clean = query_lower.replace("section", "").replace("sec", "").replace("tds on", "tds on").strip()

    # Try exact match first
    if query_clean in SECTION_MAPPING:
        return SECTION_MAPPING[query_clean]

    if query_lower in SECTION_MAPPING:
        return SECTION_MAPPING[query_lower]

    # Try matching just the section number
    # Extract numbers/letters from query
    section_num = ""
    match = __import__("re").search(r'\b(\d+[A-Za-z]{0,3})\b', query_lower)
    if match:
        section_num = match.group(1).lower()
        if section_num in SECTION_MAPPING:
            return SECTION_MAPPING[section_num]

    # Try partial match on keys
    for key, value in SECTION_MAPPING.items():
        if key in query_lower or query_lower in key:
            return value

    # Try matching any part of the query against keys
    words = query_lower.split()
    for word in words:
        if word in SECTION_MAPPING:
            return SECTION_MAPPING[word]

    return None
